const fileBuffer = await fs.readFile('invoice.xml')
const base64 = fileBuffer.toString('base64')

const response = await fetch('https://service.invoice-api.xhub.io/api/invoice/parse', {
  method: 'POST',
  headers: {
    'Authorization': 'Bearer sk_live_xxx',
    'Content-Type': 'application/json',
  },
  body: JSON.stringify({ data: base64, filename: 'invoice.xml' }),
})

const { success, invoice, detection } = await response.json()
